// delivery_status_patch_v1
// Extrae el primer 'statuses[0]' del payload de Meta Cloud API y lo normaliza.
// Si el payload no trae 'statuses', devolvemos un objeto con skip=true y el
// IF previo ya nos habrá enviado por la rama 'false', así que esto solo
// corre cuando hay statuses.
const body = $input.first().json.body || $input.first().json;
const entry = (body && body.entry && body.entry[0]) || {};
const change = (entry.changes && entry.changes[0]) || {};
const value = change.value || {};
const status = (value.statuses && value.statuses[0]) || null;

if (!status) {
  return [{ json: { skip: true, reason: 'no_status_in_payload' } }];
}

const errors = Array.isArray(status.errors) ? status.errors : [];
const firstErr = errors[0] || {};

return [{
  json: {
    provider_message_id: status.id || null,
    status: status.status || null,                  // sent | delivered | read | failed
    recipient: status.recipient_id || null,         // E.164 sin '+'
    timestamp: status.timestamp || null,            // unix seconds (string)
    error_code: firstErr.code ?? null,
    error_subcode: firstErr.error_data?.details_subcode ?? null,
    error_title: firstErr.title || null,
    error_message: firstErr.message || null,
    conversation_id: status.conversation?.id || null,
    pricing_category: status.pricing?.category || null,
  }
}];

const body = $input.first().json.body || $input.first().json;
const entry = (body.entry || [])[0];
if (!entry) return [];
const change = (entry.changes || [])[0];
if (!change || change.field !== 'messages') return [];
const value = change.value || {};
const msg = (value.messages || [])[0];
if (!msg) return [];

const contact = (value.contacts || [])[0];
const phoneNumberId = value.metadata?.phone_number_id || '';

let normalized = (msg.from || '').replace(/[\s\-\(\)\+]/g, '');
if (normalized.startsWith('0034')) normalized = normalized.slice(4);
if (normalized.length === 9) normalized = '34' + normalized;

const result = {
  from: msg.from,
  from_name: contact?.profile?.name || msg.from,
  normalized_phone: normalized,
  message_id: msg.id,
  timestamp: msg.timestamp,
  msg_type: msg.type,
  phone_number_id: phoneNumberId,
  media_id: null,
  mime_type: null,
  caption: null,
  filename: null,
  text_body: null,
  button_reply_id: null,
  button_reply_title: null
};

switch (msg.type) {
  case 'image':
    result.media_id = msg.image.id;
    result.mime_type = msg.image.mime_type;
    result.caption = msg.image.caption || null;
    result.filename = `whatsapp-${msg.from}-${Date.now()}.jpg`;
    break;
  case 'document':
    result.media_id = msg.document.id;
    result.mime_type = msg.document.mime_type;
    result.caption = msg.document.caption || null;
    result.filename = msg.document.filename || `whatsapp-${msg.from}-${Date.now()}.pdf`;
    break;
  case 'audio':
    result.media_id = msg.audio.id;
    result.mime_type = msg.audio.mime_type;
    result.filename = `voice-${msg.from}-${Date.now()}.ogg`;
    break;
  case 'text':
    result.text_body = msg.text?.body || null;
    break;
  case 'interactive':
    if (msg.interactive?.type === 'button_reply') {
      result.button_reply_id = msg.interactive.button_reply.id;
      result.button_reply_title = msg.interactive.button_reply.title;
    }
    break;
}


return [{ json: result }];

